# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string, escape
from markupsafe import Markup
import bleach

app = Flask(__name__)

ALLOWED_TAGS = ['b', 'strong', 'i', 'em', 'u', 'br']
ALLOWED_ATTRIBUTES = {}

def sanitize_html(raw_text: str) -> str:
    return bleach.clean(raw_text or '', tags=ALLOWED_TAGS, attributes=ALLOWED_ATTRIBUTES, strip=True)

@app.route('/dashboard')
def dashboard():
    name = escape(request.args.get('name', 'Guest'))
    bio = sanitize_html(request.args.get('bio', 'Welcome to your dashboard!'))
    location = escape(request.args.get('location', 'Unknown'))
    status = sanitize_html(request.args.get('status', ''))

    template = '''
    <!doctype html>
    <html lang="en">
    <head>
        <meta charset="utf-8">
        <title>Welcome Dashboard</title>
        <style>
            body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f5f8fa;color:#333;}
            .wrapper{max-width:800px;margin:60px auto;background:#fff;border-radius:8px;box-shadow:0 2px 6px rgba(0,0,0,.1);padding:40px 60px;}
            .name{font-size:2.2em;margin:0 0 10px;color:#2c3e50;}
            .location{font-size:1em;color:#7f8c8d;margin:0 0 30px;}
            .bio{font-size:1.1em;line-height:1.6;margin:0 0 25px;}
            .status{padding:15px 20px;background:#eafaf1;border-left:5px solid #2ecc71;border-radius:4px;font-size:1.1em;}
        </style>
    </head>
    <body>
        <div class="wrapper">
            <h1 class="name">{{ name }}</h1>
            <p class="location">{{ location }}</p>
            <div class="bio">{{ bio|safe }}</div>
            {% if status %}
            <div class="status">{{ status|safe }}</div>
            {% endif %}
        </div>
    </body>
    </html>
    '''
    return render_template_string(template, name=name, bio=Markup(bio), location=location, status=Markup(status))

if __name__ == '__main__':
    app.run(debug=True)